&=b_{2i}(R) (\h_{2k-1}(\xv) \yv + \h_{2k-2}(\xv) \zv).
\end{align*}

To show \eqref{eq:change3}, \eqref{eq:change4}, one should apply Proposition~\ref{pr:3VertexAlternatingMutations} to relabelings of the quivers $R|_{12i}$ instead of $Q^{(1)}|_{12n}$.
