\\
\label{eq:C12i}
& \text{$Q^{(2k+1)}|_{12i}, \ldots, Q^{(2k+n)}|_{12i}$ are acyclic,} 
\\
\label{eq:Q12iDesc}
& Q^{(0)}|_{12i} \mutation{1} Q^{(4k+n-1)}|_{12i} \mutation{2} \cdots \mutation{2} Q^{(2k+n)}|_{12i} = L|_{12i}= 
