\begin{lemma}
\label{lem:Subquiver12nLeft}
We have $Q^{(4k+n-2-j)}|_{12n} = Q^{(j+1)}|_{12n}$ for $ 0 \leq j \leq 2k$.
\end{lemma}

\begin{proof}
%We argue by descending induction on~$j$. 
