\label{eq:RLQ-L}
L&= Q^{(2k+n)}=\T{1 \cdots (n-1) (21)^k n}{Q}=\T{1 \cdots (n-1)}{R} , \\
\label{eq:Qpdef}
Q' &= Q^{(4k+n)}= \T{(1 2)^k 1 2 3 \cdots (n-2) (n-1) (2 1)^k n}{Q}. 
\end{align}

